PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE scene_cards (
    scene_id TEXT PRIMARY KEY,
    asset_id TEXT NOT NULL,
    video_title TEXT NOT NULL,
    scene_index INTEGER NOT NULL,
    scene_count INTEGER NOT NULL,

    -- 時間
    start_seconds REAL NOT NULL,
    end_seconds REAL NOT NULL,
    duration_seconds REAL NOT NULL,

    -- 維持率（実測値）
    retention_start_pct REAL,
    retention_end_pct REAL,
    retention_avg_pct REAL,
    retention_delta_pct REAL,

    -- 分類
    series TEXT NOT NULL,
    scene_type TEXT NOT NULL,
    comedy_type TEXT NOT NULL DEFAULT 'なし',
    energy INTEGER NOT NULL CHECK(energy BETWEEN 1 AND 5),
    emotion TEXT NOT NULL,
    narrative_role TEXT NOT NULL,

    -- 内容（短文）
    one_line TEXT NOT NULL,
    key_dialogue TEXT,
    comedy_mechanism TEXT,

    -- キャラクター
    characters JSON NOT NULL DEFAULT '[]',
    scene_driver TEXT,

    -- タグ
    tags JSON NOT NULL DEFAULT '[]',

    -- メタ
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, primary_comedy_type TEXT, secondary_comedy_type TEXT DEFAULT 'なし', classification_confidence REAL DEFAULT 1.0, micro_hotspots TEXT DEFAULT '[]', source_model TEXT DEFAULT 'claude-sonnet-4-20250514', ontology_version TEXT DEFAULT 'v1', scene_card_version TEXT DEFAULT 'v1', generated_at TEXT,

    FOREIGN KEY(asset_id) REFERENCES assets(id) ON DELETE CASCADE
);
COMMIT;
